pageProps.query:
    query blogPostQuery($relativePath: String!) {
  ...LayoutQueryFragment
  post(relativePath: $relativePath) {
    ...PostParts
    author {
      ... on Author {
        name
        avatar
      }
    }
  }
}

    fragment LayoutQueryFragment on Query {
  global(relativePath: "index.json") {
    ...GlobalParts
  }
}

    fragment GlobalParts on Global {
  header {
    __typename
    icon
    color
    nav {
      __typename
      href
      label
    }
  }
  theme {
    __typename
    color
    font
    icon
    darkMode
  }
}


    fragment PostParts on Post {
  title
  heroImg
  excerpt
  author {
    ... on Author {
      name
      avatar
    }
    ... on Document {
      id
    }
  }
  date
  _body
}
